ee:message.ee:set-payload:
%dw 2.0 output application/java var raw = payload.generations[0].text default ""
fun extractLine(label: String): String = ((raw splitBy "\n") filter ($ startsWith (label ++ ":")) map ($ substringAfter (label ++ ":") trim) )[0] default ""
fun toNumber(s: String): Number = if (s contains "-") ((s substringBefore "-" replace /[^0-9.]/ with "" as Number) + (s substringAfter "-" replace /[^0-9.]/ with "" as Number)) / 2 else s replace /[^0-9.]/ with "" as Number default 0 --- { selectedIdeaName: extractLine("IDEA"), fteImpact: toNumber(extractLine("FTE_IMPACT")), dollarImpact: toNumber(extractLine("DOLLAR_IMPACT")), confidenceScore: extractLine("CONFIDENCE") replace /[^0-9]/ with "" as Number default 0, effort: extractLine("EFFORT"), reasoning: extractLine("REASONING"), requiredValidations: extractLine("REQUIRED_VALIDATIONS"), rawLlmResponse: raw }

%dw 2.0
output application/json
var ctx  = vars.plantContext
var rec  = vars.recommendation
var top  = vars.scoredIdeas[0]
var idea = vars.ideaId
---
{
    blocks: [
        {
            'type': "header",
            text: {
                'type': "plain_text",
                text: "PlantIQ AI Recommendation — " ++ ctx.plantName
            }
        },
        {
            'type': "section",
            fields: [
                { 'type': "mrkdwn", text: "*Shop:*\n"     ++ ctx.shopName },
                { 'type': "mrkdwn", text: "*Quarter:*\n"  ++ ctx.quarter },
                { 'type': "mrkdwn", text: "*HQ Gap:*\n"   ++ (ctx.gapToTarget as String) ++ " FTE" },
                { 'type': "mrkdwn", text: "*Confidence:*\n" ++ (rec.confidenceScore as String) ++ "%" }
            ]
        },
        {
            'type': "section",
            text: {
                'type': "mrkdwn",
                text: "*Recommended Idea:* " ++ rec.selectedIdeaName ++
                      "\n*FTE Impact:* " ++ (rec.fteImpact as String) ++
                      " FTE  |  *$ Impact:* $" ++ (rec.dollarImpact as String) ++
                      "\n*Effort:* " ++ (rec.effort default "Medium") ++
                      "\n*Evidence:* " ++ (top.benchmarkEvidence default "No benchmarks available")
            }
        },
        {
            'type': "actions",
            elements: [
                {
                    'type': "button",
                    text: { 'type': "plain_text", text: "Approve" },
                    style: "primary",
                    action_id: "approve_idea",
                    value: idea
                },
                {
                    'type': "button",
                    text: { 'type': "plain_text", text: "Reject" },
                    style: "danger",
                    action_id: "reject_idea",
                    value: idea
                },
                {
                    'type': "button",
                    text: { 'type': "plain_text", text: "More Info" },
                    action_id: "more_info_idea",
                    value: idea
                }
            ]
        }
    ]
}
